export const LoginPage: React.FC = () => {
  const { login } = useAuth();
  const navigate = useNavigate();
  const [selectedRole, setSelectedRole] = useState<UserRole | null>(null);

  const handleLogin = () => {
    if (selectedRole) {
      login(selectedRole);
      const redirectPath = selectedRole === UserRole.MP ? '/mp' : selectedRole === UserRole.PA ? '/pa' : '/citizen';
      navigate(redirectPath);
    }
  };

  const roleConfigs = [
    { role: UserRole.MP, label: 'Member of Parliament', icon: Shield, desc: 'Access analytics and tour dashboards' },
    { role: UserRole.PA, label: 'Personal Assistant', icon: Briefcase, desc: 'Manage letters, tours, and data entry' },
    { role: UserRole.CITIZEN, label: 'Citizen Portal', icon: Users, desc: 'Submit complaints and track services' },
  ];

  return (
    <div className="min-h-screen bg-slate-50 flex items-center justify-center p-6">
      <motion.div
        initial={{ opacity: 0, scale: 0.95 }}
        animate={{ opacity: 1, scale: 1 }}
        className="max-w-md w-full"
      >
        <div className="text-center mb-8">
          <div className="w-16 h-16 bg-indigo-600 rounded-2xl flex items-center justify-center text-white font-bold mx-auto mb-4 text-2xl">MC</div>
          <h2 className="text-3xl font-bold text-slate-900">Welcome Back</h2>
          <p className="text-slate-500 mt-2">Please select your portal to continue</p>
        </div>

        <div className="bg-white p-8 rounded-2xl border border-slate-200 shadow-sm space-y-4">
          {roleConfigs.map((cfg) => (
            <button
              key={cfg.role}
              onClick={() => setSelectedRole(cfg.role)}
              className={`w-full flex items-start gap-4 p-4 rounded-xl border-2 transition-all text-left ${
                selectedRole === cfg.role ? 'border-indigo-600 bg-indigo-50' : 'border-slate-100 hover:border-slate-200'
              }`}
            >
              <div className={`p-2 rounded-lg ${selectedRole === cfg.role ? 'bg-indigo-600 text-white' : 'bg-slate-100 text-slate-500'}`}>
                <cfg.icon className="w-5 h-5" />
              </div>
              <div>
                <p className={`font-bold ${selectedRole === cfg.role ? 'text-indigo-900' : 'text-slate-900'}`}>{cfg.label}</p>
                <p className="text-sm text-slate-500">{cfg.desc}</p>
              </div>
            </button>
          ))}

          <Button 
            fullWidth 
            size="lg" 
            className="mt-6" 
            disabled={!selectedRole}
            onClick={handleLogin}
          >
            Login to Portal
          </Button>

          <div className="text-center mt-6">
            <button 
              onClick={() => navigate('/')}
              className="text-sm font-medium text-slate-400 hover:text-slate-600"
            >
              Back to main page
            </button>
          </div>
        </div>
      </motion.div>
    </div>
  );
};

