// Protected Route Wrapper
const ProtectedRoute: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const { isAuthenticated } = useAuth();
  if (!isAuthenticated) return <Navigate to="/login" replace />;
  return <>{children}</>;
};

// Main Layout Wrapper
const AppLayout: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const { isAuthenticated, user } = useAuth();
  const location = useLocation();
  const isPublicPage = location.pathname === '/' || location.pathname === '/login';

  return (
    <div className="flex min-h-screen bg-slate-50">
      {isAuthenticated && !isPublicPage && <Sidebar />}
      <main 
        className={`flex-1 transition-all duration-300 ${
          isAuthenticated && !isPublicPage ? 'pl-64' : ''
        }`}
      >
        <div className={!isPublicPage ? 'p-8 pt-10' : ''}>
          <AnimatePresence mode="wait">
            <motion.div
              key={location.pathname}
              initial={{ opacity: 0, y: 10 }}
              animate={{ opacity: 1, y: 0 }}
              exit={{ opacity: 0, y: -10 }}
              transition={{ duration: 0.3 }}
            >
              {children}
            </motion.div>
          </AnimatePresence>
        </div>
      </main>
    </div>
  );
};

const App: React.FC = () => {
  return (
    <AuthProvider>
      <HashRouter>
        <AppLayout>
          <Routes>
            <Route path="/" element={<LandingPage />} />
            <Route path="/login" element={<LoginPage />} />

            {/* MP Routes */}
            <Route path="/mp" element={<ProtectedRoute><MpDashboard /></ProtectedRoute>} />
            <Route path="/mp/tours" element={<ProtectedRoute><ToursMpPage /></ProtectedRoute>} />
            <Route path="/mp/mplads" element={<ProtectedRoute><MpladsMpPage /></ProtectedRoute>} />
            <Route path="/mp/complaints" element={<ProtectedRoute><ComplaintsMpPage /></ProtectedRoute>} />
            <Route path="/mp/media" element={<ProtectedRoute><MediaMpPage /></ProtectedRoute>} />
            <Route path="/mp/works" element={<ProtectedRoute><WorksMpPage /></ProtectedRoute>} />

            {/* PA Routes */}
            <Route path="/pa" element={<ProtectedRoute><PlaceholderPage title="PA Operations Dashboard" /></ProtectedRoute>} />
            <Route path="/pa/letters" element={<ProtectedRoute><PlaceholderPage title="Letter Drafting" /></ProtectedRoute>} />
