            <Route path="/citizen/info" element={<ProtectedRoute><PlaceholderPage title="Constituency Information" /></ProtectedRoute>} />

            {/* Fallback */}
            <Route path="*" element={<Navigate to="/" replace />} />
          </Routes>
        </AppLayout>
