export const LoginPage: React.FC = () => {
  const { login } = useAuth();
  const navigate = useNavigate();

  // States
  const [isLogin, setIsLogin] = useState(true);
  const [selectedRole, setSelectedRole] = useState<UserRole | null>(null);
  const [step, setStep] = useState(1); // 1: Role Selection, 2: Credentials
  const [isLoading, setIsLoading] = useState(false);

  const handleRoleSelect = (role: UserRole) => {
    setSelectedRole(role);
    setStep(2);
  };

  const handleAction = () => {
    setIsLoading(true);
    // Simulate API delay
    setTimeout(() => {
      if (selectedRole) {
        login(selectedRole);
        const redirectPath = 
          selectedRole === UserRole.MP ? '/mp' : 
          selectedRole === UserRole.PA ? '/pa' : 
          selectedRole === UserRole.STAFF ? '/staff' : 
          '/citizen';
        navigate(redirectPath);
      }
      setIsLoading(false);
    }, 1200);
  };

  const roleConfigs = [
    { role: UserRole.MP, label: 'Member of Parliament', icon: Shield, desc: 'Constituency Control' },
    { role: UserRole.PA, label: 'Personal Assistant', icon: Briefcase, desc: 'Protocol & Scheduling' },
    { role: UserRole.STAFF, label: 'Office Staff', icon: Layers, desc: 'Operations & Verification' },
    { role: UserRole.CITIZEN, label: 'Constituent Portal', icon: Users, desc: 'Grievances & Services' },
  ];

  const containerVariants = {
    hidden: { opacity: 0, y: 20 },
    visible: { 
      opacity: 1, 
      y: 0,
      transition: { 
        duration: 0.6,
        staggerChildren: 0.1
      }
    },
    exit: { opacity: 0, y: -20, transition: { duration: 0.3 } }
  };

  const itemVariants = {
    hidden: { opacity: 0, x: -10 },
    visible: { opacity: 1, x: 0 }
  };

  return (
    <div className="min-h-screen bg-[#fcfdfe] flex items-center justify-center p-4 relative overflow-hidden font-['Plus_Jakarta_Sans']">
      {/* Background Orbs */}
      <div className="absolute top-[-10%] left-[-5%] w-[40%] h-[40%] bg-indigo-50/50 rounded-full blur-[120px] -z-10" />
      <div className="absolute bottom-[-10%] right-[-5%] w-[40%] h-[40%] bg-indigo-100/30 rounded-full blur-[120px] -z-10" />

      <motion.div
        initial="hidden"
        animate="visible"
        variants={containerVariants}
        className="w-full max-w-[1000px] bg-white rounded-[3rem] shadow-[0_32px_64px_-16px_rgba(0,0,0,0.08)] border border-slate-100 overflow-hidden flex flex-col md:flex-row min-h-[650px]"
      >
        {/* Left Side: Brand & Context */}
        <div className="md:w-5/12 bg-slate-900 p-12 text-white flex flex-col justify-between relative overflow-hidden">
          <div className="absolute top-0 left-0 w-full h-full opacity-20 pointer-events-none" 
               style={{ backgroundImage: 'radial-gradient(circle at 2px 2px, #4f46e5 1px, transparent 0)', backgroundSize: '24px 24px' }} />

          <div className="relative z-10">
            <div className="w-14 h-14 bg-indigo-600 rounded-2xl flex items-center justify-center font-black text-2xl mb-8 shadow-xl shadow-indigo-900/50">MC</div>
            <h1 className="text-4xl font-black tracking-tighter mb-4">MP Connect</h1>
            <p className="text-slate-400 font-medium leading-relaxed">
              The digital gateway to constituency governance. Real-time transparency between the Hon. Member of Parliament and the people.
            </p>
          </div>

          <div className="relative z-10">
            <div className="space-y-4">
              <div className="flex items-center gap-3 text-sm font-bold">
                <div className="w-8 h-8 rounded-full bg-white/10 flex items-center justify-center text-indigo-400">
                  <Fingerprint className="w-4 h-4" />
                </div>
                End-to-End Encrypted Access
              </div>
              <div className="flex items-center gap-3 text-sm font-bold">
                <div className="w-8 h-8 rounded-full bg-white/10 flex items-center justify-center text-green-400">
                  <CheckCircle2 className="w-4 h-4" />
                </div>
                Official Government Protocol
              </div>
            </div>
          </div>
        </div>

        {/* Right Side: Action Forms */}
        <div className="md:w-7/12 p-8 md:p-16 flex flex-col relative bg-white">
          {/* Header Toggle */}
