                  <p className="text-slate-500 font-medium mt-1">Select your role to continue</p>
                </div>

                <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                  {roleConfigs.map((cfg) => (
                    <motion.button
                      key={cfg.role}
                      variants={itemVariants}
                      whileHover={{ y: -4, scale: 1.02 }}
                      whileTap={{ scale: 0.98 }}
                      onClick={() => handleRoleSelect(cfg.role)}
                      className={`group flex flex-col p-5 rounded-3xl border-2 transition-all text-left relative ${
                        selectedRole === cfg.role 
                          ? 'border-indigo-600 bg-indigo-50/50 shadow-indigo-100 shadow-lg' 
                          : 'border-slate-100 hover:border-indigo-200 bg-white shadow-sm'
                      }`}
                    >
                      <div className={`w-10 h-10 rounded-xl flex items-center justify-center mb-4 transition-colors ${
                        selectedRole === cfg.role ? 'bg-indigo-600 text-white' : 'bg-slate-100 text-slate-500 group-hover:bg-indigo-100 group-hover:text-indigo-600'
                      }`}>
                        <cfg.icon className="w-5 h-5" />
                      </div>
                      <h4 className="font-black text-slate-900 text-sm tracking-tight">{cfg.label}</h4>
                      <p className="text-[10px] text-slate-400 font-bold uppercase tracking-wide mt-1">{cfg.desc}</p>

                      {selectedRole === cfg.role && (
                        <div className="absolute top-4 right-4">
                           <div className="w-2 h-2 rounded-full bg-indigo-600 animate-ping" />
                        </div>
                      )}
                    </motion.button>
                  ))}
                </div>
              </motion.div>
            ) : (
              <motion.div
                key="step2"
                initial={{ opacity: 0, x: 20 }}
                animate={{ opacity: 1, x: 0 }}
                exit={{ opacity: 0, x: -20 }}
                className="space-y-8"
              >
                <div>
                  <div className="flex items-center gap-3 mb-2">
                    <div className="px-3 py-1 bg-indigo-100 text-indigo-700 text-[10px] font-black uppercase rounded-lg tracking-widest">
                      {selectedRole} Access
                    </div>
                  </div>
                  <h2 className="text-3xl font-black text-slate-900 tracking-tight">
                    {isLogin ? 'Identity Verification' : 'Account Details'}
                  </h2>
                </div>

                <div className="space-y-5">
                  {!isLogin && (
                    <div className="space-y-1.5">
                      <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Full Official Name</label>
                      <div className="relative">
                        <User className="w-4 h-4 absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" />
                        <input 
                          type="text" 
                          placeholder="Hon. Rahul Kumar / Anand Sharma"
                          className="w-full pl-11 pr-4 py-4 bg-slate-50 border border-slate-100 rounded-2xl outline-none font-bold text-sm focus:ring-2 focus:ring-indigo-500 transition-all"
                        />
                      </div>
                    </div>
                  )}

                  <div className="space-y-1.5">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Email Address</label>
                    <div className="relative">
                      <Mail className="w-4 h-4 absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" />
                      <input 
                        type="email" 
                        placeholder="office@constituency.gov"
                        className="w-full pl-11 pr-4 py-4 bg-slate-50 border border-slate-100 rounded-2xl outline-none font-bold text-sm focus:ring-2 focus:ring-indigo-500 transition-all"
                      />
                    </div>
                  </div>

                  <div className="space-y-1.5">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Secure Password</label>
                    <div className="relative">
                      <Lock className="w-4 h-4 absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" />
                      <input 
                        type="password" 
                        placeholder="••••••••••••"
                        className="w-full pl-11 pr-4 py-4 bg-slate-50 border border-slate-100 rounded-2xl outline-none font-bold text-sm focus:ring-2 focus:ring-indigo-500 transition-all"
                      />
                    </div>
                  </div>

                  {/* Role Specific Secure Fields */}
                  {!isLogin && selectedRole !== UserRole.CITIZEN && (
                    <div className="space-y-1.5 animate-in fade-in slide-in-from-bottom-2">
                      <label className="text-[10px] font-black text-indigo-500 uppercase tracking-widest ml-1">Department Invitation Code</label>
                      <div className="relative">
                        <Key className="w-4 h-4 absolute left-4 top-1/2 -translate-y-1/2 text-indigo-400" />
                        <input 
                          type="text" 
                          placeholder="DEPT-XXXX-XXXX"
                          className="w-full pl-11 pr-4 py-4 bg-indigo-50/30 border border-indigo-100 rounded-2xl outline-none font-bold text-sm focus:ring-2 focus:ring-indigo-500 transition-all"
                        />
                      </div>
                    </div>
                  )}

                  {!isLogin && selectedRole === UserRole.CITIZEN && (
                    <div className="space-y-1.5">
                      <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Mobile Number (OTP)</label>
                      <div className="relative">
                        <Smartphone className="w-4 h-4 absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" />
                        <input 
                          type="tel" 
                          placeholder="+91 9XXXX XXXXX"
                          className="w-full pl-11 pr-4 py-4 bg-slate-50 border border-slate-100 rounded-2xl outline-none font-bold text-sm focus:ring-2 focus:ring-indigo-500 transition-all"
                        />
                      </div>
                    </div>
                  )}

                  <Button 
                    fullWidth 
                    size="lg" 
                    className="h-14 rounded-2xl shadow-xl shadow-indigo-100 mt-4" 
                    onClick={handleAction}
                    disabled={isLoading}
                  >
                    {isLoading ? (
                      <div className="flex items-center gap-2">
                        <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                        Validating Identity...
                      </div>
                    ) : (
                      <div className="flex items-center gap-2">
                        {isLogin ? 'Enter Portal' : 'Create My Account'}
                        <ArrowRight className="w-4 h-4" />
                      </div>
                    )}
                  </Button>
                </div>
              </motion.div>
            )}
          </AnimatePresence>

          {/* Footer Info */}
          <div className="mt-auto pt-8 flex items-center justify-between">
