            >
              Back to landing
            </button>
            <p className="text-[10px] font-bold text-slate-300 uppercase tracking-widest">
              NIC • DIGITAL INDIA v3.0
            </p>
          </div>
        </div>
      </motion.div>

      {/* Trust Badges */}
      <div className="absolute bottom-8 flex gap-8 opacity-20 grayscale pointer-events-none">
         <div className="text-xs font-black uppercase tracking-widest">G20 • ONE EARTH</div>
         <div className="text-xs font-black uppercase tracking-widest">MINISTRY OF ELECTRONICS & IT</div>
      </div>
    </div>
  );
};

import React from 'react';
