interface LoginPageProps {
  portalType: 'citizen' | 'official';
}

export const LoginPage: React.FC<LoginPageProps> = ({ portalType }) => {
  const { login } = useAuth();
  const navigate = useNavigate();

  // States
  const [isLogin, setIsLogin] = useState(true);
  const [selectedRole, setSelectedRole] = useState<UserRole | null>(null);
  const [step, setStep] = useState(1); 
  const [isLoading, setIsLoading] = useState(false);

  // Filter roles based on portal type
  const roleConfigs = [
    { role: UserRole.MP, label: 'Member of Parliament', icon: Shield, desc: 'Constituency Control', type: 'official' },
    { role: UserRole.PA, label: 'Personal Assistant', icon: Briefcase, desc: 'Protocol & Scheduling', type: 'official' },
    { role: UserRole.STAFF, label: 'Office Staff', icon: Layers, desc: 'Operations & Verification', type: 'official' },
    { role: UserRole.CITIZEN, label: 'Constituent Portal', icon: Users, desc: 'Grievances & Services', type: 'citizen' },
  ].filter(cfg => cfg.type === portalType);

  // If there's only one role (citizen portal), skip role selection step
  useEffect(() => {
    if (portalType === 'citizen') {
      setSelectedRole(UserRole.CITIZEN);
      setStep(2);
    } else {
      setSelectedRole(null);
      setStep(1);
    }
  }, [portalType]);

  const handleRoleSelect = (role: UserRole) => {
    setSelectedRole(role);
    setStep(2);
  };

  const handleAction = () => {
    setIsLoading(true);
    setTimeout(() => {
      if (selectedRole) {
        login(selectedRole);
        const redirectPath = 
          selectedRole === UserRole.MP ? '/mp' : 
          selectedRole === UserRole.PA ? '/pa' : 
          selectedRole === UserRole.STAFF ? '/staff' : 
          '/citizen';
        navigate(redirectPath);
      }
      setIsLoading(false);
    }, 1200);
  };

  const containerVariants = {
    hidden: { opacity: 0, y: 20 },
    visible: { 
      opacity: 1, 
      y: 0,
      transition: { duration: 0.6, staggerChildren: 0.1 }
    },
    exit: { opacity: 0, y: -20, transition: { duration: 0.3 } }
  };

  const itemVariants = {
    hidden: { opacity: 0, x: -10 },
    visible: { opacity: 1, x: 0 }
  };

  return (
    <div className="min-h-screen flex items-center justify-center p-4 relative overflow-hidden font-['Plus_Jakarta_Sans'] bg-sky-50/50">

      {/* Background Decorative Orbs - Light Sky Tints */}
      <div className="absolute top-[-10%] left-[-5%] w-[40%] h-[40%] bg-sky-100/40 rounded-full blur-[120px] -z-10" />
      <div className="absolute bottom-[-10%] right-[-5%] w-[40%] h-[40%] bg-sky-200/20 rounded-full blur-[120px] -z-10" />

      <motion.div
        key={portalType}
        initial="hidden"
        animate="visible"
        variants={containerVariants}
        className="w-full max-w-[1050px] bg-white rounded-[3.5rem] shadow-[0_32px_80px_-16px_rgba(14,165,233,0.15)] border border-sky-100 overflow-hidden flex flex-col md:flex-row min-h-[700px]"
      >
        {/* Left Side: Brand & Context - High Contrast Sky Blue */}
        <div className="md:w-5/12 p-12 text-white flex flex-col justify-between relative overflow-hidden bg-sky-600">
          {/* Subtle Grid Pattern */}
          <div className="absolute top-0 left-0 w-full h-full opacity-10 pointer-events-none" 
               style={{ backgroundImage: 'radial-gradient(circle at 2px 2px, white 1px, transparent 0)', backgroundSize: '32px 32px' }} />

          <div className="relative z-10">
            <div className="w-16 h-16 bg-white rounded-3xl flex items-center justify-center font-black text-2xl mb-10 shadow-xl shadow-sky-800/20 text-sky-600">
              MC
            </div>
            <h1 className="text-5xl font-[900] tracking-tighter mb-6 leading-none">
              {portalType === 'citizen' ? 'Citizen Gateway' : 'Official Portal'}
            </h1>
            <p className="text-sky-50 font-medium leading-relaxed text-lg">
              {portalType === 'citizen' 
                ? 'Empowering constituents with direct, transparent access to legislative services and grievance resolution.'
                : 'Secure administrative backbone for the Hon. Member of Parliament and authorized executive delegates.'}
            </p>
          </div>

          <div className="relative z-10">
            <div className="space-y-5">
              <div className="flex items-center gap-4 text-sm font-black">
                <div className="w-10 h-10 rounded-2xl bg-white/10 backdrop-blur-md flex items-center justify-center text-white border border-white/20">
                  <Fingerprint className="w-5 h-5" />
                </div>
                <span>SSL Secured Protocol</span>
              </div>
              <div className="flex items-center gap-4 text-sm font-black">
                <div className="w-10 h-10 rounded-2xl bg-white/10 backdrop-blur-md flex items-center justify-center text-white border border-white/20">
                  <CheckCircle2 className="w-5 h-5" />
                </div>
                <span>NIC Compliance Verified</span>
              </div>
            </div>
          </div>
        </div>

        {/* Right Side: Forms - Clean Light Mode */}
        <div className="md:w-7/12 p-8 md:p-16 flex flex-col relative bg-white">
          {/* Header Toggle */}
          <div className="flex justify-between items-center mb-12">
            <div className="bg-sky-50 p-1.5 rounded-2xl flex">
              <button 
                onClick={() => { setIsLogin(true); setStep(portalType === 'citizen' ? 2 : 1); }}
                className={`px-8 py-2.5 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${isLogin ? 'bg-white text-sky-600 shadow-sm border border-sky-100' : 'text-sky-900/40 hover:text-sky-600'}`}
              >
                Sign In
              </button>
              <button 
                onClick={() => { setIsLogin(false); setStep(portalType === 'citizen' ? 2 : 1); }}
                className={`px-8 py-2.5 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${!isLogin ? 'bg-white text-sky-600 shadow-sm border border-sky-100' : 'text-sky-900/40 hover:text-sky-600'}`}
              >
                Register
