            </div>
            {step === 2 && portalType === 'official' && (
              <button 
                onClick={() => setStep(1)}
                className="flex items-center gap-2 text-[10px] font-black text-sky-400 hover:text-sky-600 transition-colors uppercase tracking-[0.2em]"
              >
                <ChevronLeft className="w-4 h-4" /> Change Role
              </button>
            )}
          </div>

          <AnimatePresence mode="wait">
            {step === 1 ? (
              <motion.div
                key="step1"
                initial={{ opacity: 0, x: 20 }}
                animate={{ opacity: 1, x: 0 }}
                exit={{ opacity: 0, x: -20 }}
                className="space-y-10"
