          {/* Grid Pattern Overlay */}
          <div className="absolute top-0 left-0 w-full h-full opacity-10 pointer-events-none" 
               style={{ backgroundImage: 'radial-gradient(circle at 2px 2px, white 1px, transparent 0)', backgroundSize: '32px 32px' }} />

          <div className="relative z-10">
            <div className="w-16 h-16 bg-white rounded-3xl flex items-center justify-center font-black text-2xl mb-10 shadow-xl shadow-sky-950/20 text-sky-700">
              MC
            </div>
            <h1 className="text-5xl font-[900] tracking-tighter mb-6 leading-none text-white">
              {portalType === 'citizen' ? 'Citizen Gateway' : 'Official Portal'}
            </h1>
            <p className="text-sky-50 font-medium leading-relaxed text-lg opacity-90">
              {portalType === 'citizen' 
                ? 'Empowering constituents with direct, transparent access to legislative services and grievance resolution.'
                : 'Secure administrative backbone for the Hon. Member of Parliament and authorized executive delegates.'}
            </p>
          </div>

          <div className="relative z-10">
            <div className="space-y-5">
              <div className="flex items-center gap-4 text-sm font-black text-white">
                <div className="w-10 h-10 rounded-2xl bg-white/15 backdrop-blur-md flex items-center justify-center text-white border border-white/20">
                  <Fingerprint className="w-5 h-5" />
                </div>
                <span>SSL Secured Protocol</span>
              </div>
              <div className="flex items-center gap-4 text-sm font-black text-white">
                <div className="w-10 h-10 rounded-2xl bg-white/15 backdrop-blur-md flex items-center justify-center text-white border border-white/20">
                  <CheckCircle2 className="w-5 h-5" />
                </div>
                <span>NIC Compliance Verified</span>
              </div>
            </div>
          </div>
        </div>

        {/* Right Side: Form Area - Clean White with Deep Blue Typography */}
        <div className="md:w-7/12 p-8 md:p-16 flex flex-col relative bg-white">
          <div className="flex justify-between items-center mb-12">
            <div className="bg-sky-50 p-1.5 rounded-2xl flex border border-sky-100/50">
              <button 
                onClick={() => { setIsLogin(true); setStep(portalType === 'citizen' ? 2 : 1); }}
                className={`px-8 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-[0.1em] transition-all ${isLogin ? 'bg-white text-sky-700 shadow-sm border border-sky-100' : 'text-slate-500 hover:text-sky-700'}`}
              >
                Sign In
              </button>
              <button 
                onClick={() => { setIsLogin(false); setStep(portalType === 'citizen' ? 2 : 1); }}
                className={`px-8 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-[0.1em] transition-all ${!isLogin ? 'bg-white text-sky-700 shadow-sm border border-sky-100' : 'text-slate-500 hover:text-sky-700'}`}
              >
                Register
              </button>
            </div>
            {step === 2 && portalType === 'official' && (
              <button 
                onClick={() => setStep(1)}
                className="flex items-center gap-2 text-[10px] font-black text-sky-700 hover:text-sky-950 transition-colors uppercase tracking-[0.2em]"
              >
                <ChevronLeft className="w-4 h-4" /> Change Role
              </button>
            )}
          </div>

          <AnimatePresence mode="wait">
            {step === 1 ? (
              <motion.div
                key="step1"
                initial={{ opacity: 0, x: 20 }}
                animate={{ opacity: 1, x: 0 }}
                exit={{ opacity: 0, x: -20 }}
                className="space-y-10"
              >
                <div>
                   <div className="flex items-center gap-2 mb-3">
                      <ShieldAlert className="w-4 h-4 text-sky-700" />
                      <span className="text-[10px] font-black uppercase text-sky-900/60 tracking-widest">Authorized Access Only</span>
                   </div>
                  <h2 className="text-4xl font-[900] text-sky-950 tracking-tighter">
                    Official Designation
                  </h2>
                  <p className="text-slate-700 font-medium mt-2">Identify your administrative role to proceed.</p>
                </div>

                <div className="grid grid-cols-1 gap-4">
                  {roleConfigs.map((cfg) => (
                    <motion.button
                      key={cfg.role}
                      variants={itemVariants}
                      whileHover={{ x: 8 }}
                      whileTap={{ scale: 0.98 }}
                      onClick={() => handleRoleSelect(cfg.role)}
                      className={`group flex items-center p-7 rounded-[2rem] border-2 transition-all text-left relative ${
                        selectedRole === cfg.role 
                          ? 'border-sky-600 bg-sky-50 shadow-xl shadow-sky-500/5' 
                          : 'border-slate-50 hover:border-sky-200 bg-white'
                      }`}
                    >
                      <div className={`w-14 h-14 rounded-2xl flex items-center justify-center mr-6 transition-colors ${
                        selectedRole === cfg.role ? 'bg-sky-600 text-white shadow-lg shadow-sky-200' : 'bg-sky-50 text-sky-700 group-hover:bg-sky-600 group-hover:text-white'
                      }`}>
                        <cfg.icon className="w-7 h-7" />
                      </div>
                      <div>
                        <h4 className="font-black text-sky-950 text-xl tracking-tight">{cfg.label}</h4>
                        <p className="text-[10px] text-sky-900/60 font-black uppercase tracking-widest mt-1">{cfg.desc}</p>
                      </div>
                      <ArrowRight className="ml-auto w-6 h-6 text-sky-300 group-hover:text-sky-600 transition-colors" />
                    </motion.button>
                  ))}
                </div>
              </motion.div>
            ) : (
              <motion.div
                key="step2"
                initial={{ opacity: 0, x: 20 }}
                animate={{ opacity: 1, x: 0 }}
                exit={{ opacity: 0, x: -20 }}
                className="space-y-8"
              >
                <div>
                  <div className="flex items-center gap-3 mb-3">
                    <div className="px-4 py-1 text-[10px] font-black uppercase rounded-full tracking-[0.2em] bg-sky-600 text-white shadow-lg shadow-sky-100">
                      {selectedRole === UserRole.CITIZEN ? 'Constituent Access' : `${selectedRole} Secure Key`}
                    </div>
                  </div>
                  <h2 className="text-4xl font-[900] text-sky-950 tracking-tighter">
                    {isLogin ? 'Enter Credentials' : 'Create Credentials'}
                  </h2>
                </div>

                <div className="space-y-6">
                  {!isLogin && (
                    <div className="space-y-2">
                      <label className="text-[10px] font-black text-sky-900/80 uppercase tracking-widest ml-2">
                        Full Legal Identity
                      </label>
                      <div className="relative">
                        <User className="w-5 h-5 absolute left-5 top-1/2 -translate-y-1/2 text-sky-600" />
                        <input 
                          type="text" 
                          placeholder="As per Government Records"
                          className="w-full pl-14 pr-6 py-4 bg-sky-50/50 border border-sky-100 rounded-2xl outline-none font-black text-sm focus:border-sky-500 focus:bg-white transition-all text-sky-950 placeholder:text-slate-400"
                        />
                      </div>
                    </div>
                  )}

                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-sky-900/80 uppercase tracking-widest ml-2">Registered Email</label>
                    <div className="relative">
                      <Mail className="w-5 h-5 absolute left-5 top-1/2 -translate-y-1/2 text-sky-600" />
                      <input 
                        type="email" 
                        placeholder="yourname@domain.gov.in"
                        className="w-full pl-14 pr-6 py-4 bg-sky-50/50 border border-sky-100 rounded-2xl outline-none font-black text-sm focus:border-sky-500 focus:bg-white transition-all text-sky-950 placeholder:text-slate-400"
                      />
                    </div>
                  </div>

                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-sky-900/80 uppercase tracking-widest ml-2">Secure Passkey</label>
                    <div className="relative">
                      <Lock className="w-5 h-5 absolute left-5 top-1/2 -translate-y-1/2 text-sky-600" />
                      <input 
                        type="password" 
                        placeholder="••••••••••••"
                        className="w-full pl-14 pr-6 py-4 bg-sky-50/50 border border-sky-100 rounded-2xl outline-none font-black text-sm focus:border-sky-500 focus:bg-white transition-all text-sky-950 placeholder:text-slate-400"
                      />
                    </div>
                  </div>

                  {!isLogin && portalType === 'official' && (
                    <div className="space-y-2">
                      <label className="text-[10px] font-black text-sky-800 uppercase tracking-widest ml-2">Departmental Auth Token</label>
                      <div className="relative">
                        <Key className="w-5 h-5 absolute left-5 top-1/2 -translate-y-1/2 text-sky-700" />
                        <input 
                          type="text" 
                          placeholder="AUTH-DEPT-XXXX"
                          className="w-full pl-14 pr-6 py-4 bg-sky-50 border border-sky-200 rounded-2xl outline-none font-black text-sm focus:border-sky-500 focus:bg-white transition-all text-sky-950 placeholder:text-slate-400"
                        />
                      </div>
                    </div>
                  )}

                  {!isLogin && portalType === 'citizen' && (
                    <div className="space-y-2">
                      <label className="text-[10px] font-black text-sky-900/80 uppercase tracking-widest ml-2">Active Mobile (OTP Sync)</label>
                      <div className="relative">
                        <Smartphone className="w-5 h-5 absolute left-5 top-1/2 -translate-y-1/2 text-sky-600" />
                        <input 
                          type="tel" 
                          placeholder="+91 XXXXX XXXXX"
                          className="w-full pl-14 pr-6 py-4 bg-sky-50/50 border border-sky-100 rounded-2xl outline-none font-black text-sm focus:border-sky-500 focus:bg-white transition-all text-sky-950 placeholder:text-slate-400"
                        />
                      </div>
                    </div>
                  )}

                  <Button 
                    fullWidth 
                    size="lg" 
                    className="h-16 rounded-[1.5rem] shadow-2xl shadow-sky-200 mt-6 bg-sky-600 font-black text-lg text-white" 
                    onClick={handleAction}
                    disabled={isLoading}
                  >
                    {isLoading ? (
                      <div className="flex items-center gap-3">
                        <div className="w-5 h-5 border-3 border-white/30 border-t-white rounded-full animate-spin" />
                        Validating...
                      </div>
                    ) : (
                      <div className="flex items-center gap-2">
                        {isLogin ? 'Enter Official Portal' : 'Register Official Account'}
                        <ArrowRight className="w-5 h-5" />
                      </div>
                    )}
                  </Button>
                </div>
              </motion.div>
            )}
          </AnimatePresence>

          <div className="mt-auto pt-10 flex items-center justify-between border-t border-sky-50">
            <button 
              onClick={() => navigate('/')}
              className="text-[10px] font-black text-sky-700 hover:text-sky-950 transition-colors uppercase tracking-[0.3em]"
            >
              Back to Surface
            </button>
            <p className="text-[10px] font-black text-sky-950/40 uppercase tracking-[0.3em]">
              Powered by NIC-GovCloud v4
            </p>
          </div>
        </div>
      </motion.div>
    </div>
  );
};
